var fishkaCurrent = 0;
var fishkaTotal = 0;

function fishkaGo(i) {
  fishkaCurrent = i;
  fishkaUpdate();
}

function fishkaNext() {
  fishkaCurrent = (fishkaCurrent + 1) % fishkaTotal;
  fishkaUpdate();
}

function fishkaPrev() {
  fishkaCurrent = (fishkaCurrent - 1 + fishkaTotal) % fishkaTotal;
  fishkaUpdate();
}

function fishkaUpdate() {
  var track = document.getElementById('fishka-carousel-track');
  if (track) {
    track.style.transform = 'translateX(-' + (fishkaCurrent * 100) + '%)';
  }
  
  for (var i = 0; i < fishkaTotal; i++) {
    var dot = document.getElementById('dot-' + i);
    if (dot) {
      if (i === fishkaCurrent) {
        dot.style.background = '#46b9a7';
        dot.style.width = '28px';
        dot.style.height = '10px';
        dot.style.borderRadius = '5px';
      } else {
        dot.style.background = 'rgba(255,255,255,0.3)';
        dot.style.width = '10px';
        dot.style.height = '10px';
        dot.style.borderRadius = '50%';
      }
    }
  }
}

function fishkaInitDots() {
  var dotsContainer = document.getElementById('fishka-dots-container');
  if (!dotsContainer) return;
  
  dotsContainer.innerHTML = '';
  
  for (var i = 0; i < fishkaTotal; i++) {
    var dot = document.createElement('button');
    dot.id = 'dot-' + i;
    dot.style.cssText = 'width: 10px; height: 10px; border-radius: 50%; background: rgba(255, 255, 255, 0.3); border: none; cursor: pointer; transition: 0.3s; padding: 0px;';
    
    (function(index) {
      dot.addEventListener('click', function() { fishkaGo(index); });
    })(i);
    
    dotsContainer.appendChild(dot);
  }
}

// Инициализация после загрузки DOM
document.addEventListener('DOMContentLoaded', function() {
  // Автоматически определяем количество слайдов
  var track = document.getElementById('fishka-carousel-track');
  if (track) {
    fishkaTotal = track.children.length;
  }
  
  // Создаем точки навигации
  fishkaInitDots();
  
  // Устанавливаем начальное состояние
  fishkaUpdate();
  
  // Привязываем обработчики к кнопкам
  var prevBtn = document.getElementById('fishka-prev-btn');
  var nextBtn = document.getElementById('fishka-next-btn');
  
  if (prevBtn) prevBtn.addEventListener('click', fishkaPrev);
  if (nextBtn) nextBtn.addEventListener('click', fishkaNext);
  
  // Автопрокрутка каждые 4 секунды
  setInterval(fishkaNext, 4000);
  


  
  // Автовоспроизведение ТОЛЬКО фулскрин Rutube видео (с id="rutube-player")
  var rutubeIframe = document.getElementById('rutube-player');
  if (rutubeIframe) {
    // Попытка 1: Используем Rutube Player API
    try {
      rutubeIframe.contentWindow.postMessage('{"type":"player:play","data":{}}', '*');
    } catch(e) {}
    
    // Попытка 2: Перезагружаем iframe с правильными параметрами
    var currentSrc = rutubeIframe.src;
    if (currentSrc.indexOf('&t=1') === -1) {
      // Добавляем таймстамп чтобы обойти кеш и заставить перезагрузить
      var newSrc = currentSrc + '&t=1';
      setTimeout(function() {
        rutubeIframe.src = newSrc;
      }, 100);
    }
    
    // Попытка 3: Автозапуск при скролле до видео
    var videoObserver = new IntersectionObserver(function(entries) {
      entries.forEach(function(entry) {
        if (entry.isIntersecting) {
          var iframe = entry.target;
          // Используем Rutube API
          try {
            iframe.contentWindow.postMessage('{"type":"player:play","data":{}}', '*');
          } catch(e) {}
          
          // Перезагружаем iframe при появлении в зоне видимости
          var src = iframe.getAttribute('src');
          if (src && src.indexOf('&play=1') === -1) {
            iframe.src = src + '&play=1';
          }
        }
      });
    }, { threshold: 0.25 });
    
    videoObserver.observe(rutubeIframe);
    
    // Попытка 4: Клик по странице запускает видео
    var playOnInteraction = function() {
      try {
        rutubeIframe.contentWindow.postMessage('{"type":"player:play","data":{}}', '*');
      } catch(e) {}
      document.removeEventListener('click', playOnInteraction);
      document.removeEventListener('scroll', playOnInteraction);
    };
    
    document.addEventListener('click', playOnInteraction, { once: true });
    document.addEventListener('scroll', playOnInteraction, { once: true });
  }
});




// Эффект падающих фишек (оптимизированные base64 изображения)
(function() {
  // Группы фишек с base64 данными
  var fishkaGroups = {
    cat: [
      'data:image/png;base64,',
      'data:image/png;base64,',
      'data:image/png;base64,',
      'data:image/png;base64,',
      'data:image/png;base64,',
      'data:image/png;base64,',
    ],
    dog: [
      'data:image/png;base64,',
      'data:image/png;base64,',
    ],
    logo: [
      'data:image/png;base64,',
      'data:image/png;base64,',
      'data:image/png;base64,',
      'data:image/png;base64,',
      'data:image/png;base64,',
      'data:image/png;base64,',
    ],
    sam: [
      'data:image/png;base64,',
      'data:image/png;base64,',
    ],
    tom: [
      'data:image/png;base64,',
      'data:image/png;base64,',
    ],
    tost: [
      'data:image/png;base64,',
      'data:image/png;base64,',
    ],
  };
  
  var fishkaContainer = document.createElement('div');
  fishkaContainer.id = 'fishka-container';
  fishkaContainer.style.cssText = 'position: absolute; top: 0; left: 0; width: 100%; height: 100%; pointer-events: none; overflow: hidden; z-index: 1;';
  
  // Ждем загрузки DOM
  document.addEventListener('DOMContentLoaded', function() {
    var heroSection = document.querySelector('section');
    if (heroSection) {
      heroSection.appendChild(fishkaContainer);
      createFishkas();
    }
  });
  
  function createFishkas() {
    var fishkaCount = 12; // Количество падающих фишек
    
    for (var i = 0; i < fishkaCount; i++) {
      setTimeout(function() {
        createFishka();
      }, i * 250);
    }
    
    // Продолжаем создавать новые фишки
    setInterval(function() {
      createFishka();
    }, 1000);
  }
  
  function createFishka() {
    // Выбираем случайную группу фишек
    var groupNames = Object.keys(fishkaGroups);
    var randomGroup = groupNames[Math.floor(Math.random() * groupNames.length)];
    var frames = fishkaGroups[randomGroup];
    
    var fishka = document.createElement('img');
    var size = Math.random() * 25 + 35; // Размер от 35 до 60px
    var startX = Math.random() * 100;
    var duration = Math.random() * 4 + 7; // 7-11 секунд
    var delay = Math.random() * 0.5;
    var drift = (Math.random() - 0.5) * 120;
    var rotation = Math.random() * 360;
    var rotationSpeed = (Math.random() - 0.5) * 600;
    
    // Выбираем случайный кадр из группы
    var randomFrame = frames[Math.floor(Math.random() * frames.length)];
    fishka.src = randomFrame;
    
    fishka.style.cssText = 
      'position: absolute; ' +
      'top: -80px; ' +
      'left: ' + startX + '%; ' +
      'width: ' + size + 'px; ' +
      'height: auto; ' +
      'opacity: 0.8; ' +
      'filter: drop-shadow(0 2px 6px rgba(0,0,0,0.25));';
    
    var animationName = 'fishkafall-' + Math.random().toString(36).substr(2, 9);
    var keyframes = 
      '@keyframes ' + animationName + ' {' +
        '0% { transform: translateY(0) translateX(0) rotate(' + rotation + 'deg); }' +
        '100% { transform: translateY(calc(100vh + 80px)) translateX(' + drift + 'px) rotate(' + (rotation + rotationSpeed) + 'deg); }' +
      '}';
    
    var style = document.createElement('style');
    style.textContent = keyframes;
    document.head.appendChild(style);
    
    fishka.style.animation = animationName + ' ' + duration + 's linear ' + delay + 's forwards';
    
    var container = document.getElementById('fishka-container');
    if (container) {
      container.appendChild(fishka);
      
      setTimeout(function() {
        if (fishka.parentNode) {
          fishka.parentNode.removeChild(fishka);
          document.head.removeChild(style);
        }
      }, (duration + delay) * 1000 + 100);
    }
  }
})();
